import React from 'react';

const Awards = () => {


  return (
    <section id="awards" className="awards">
      <h2>Awards</h2>
      <div>
        {awards.map((award, index) => (
          <div key={index} className="award">
            <h3>{award.title}</h3>
            <p>Issued by: {award.issuer}</p>
            <p>Date: {award.date}</p>
          </div>
        ))}
      </div>
    </section>
  );
};

export default Awards;
